import React from 'react';
import uuid from '../../../utils/uuid';
import Accordion from '../../atoms/Accordion';
import Container from '../../atoms/Container';
import Header from '../../molecules/Header';

export type Question = {
  category: string;
  question: string;
  answers: Array<string>;
};

export type FAQProps = {
  id: string;
  title: string;
  subtitle: string;
  questions: Array<Question>;
};

const FAQ: React.FC<FAQProps> = ({
  id,
  title,
  subtitle,
  questions
}: FAQProps) => {
  return (
    <div id={id} className="pb-16">
      <Container>
        <Header subtitle={subtitle}>{title}</Header>
        <Accordion>
          <>
            {questions.map(
              (
                { question = '', answers = [], category = '' }: Question,
                index: number,
                array: Array<Question>
              ) => {
                const border: string =
                  index === array.length - 1 ? '' : 'border-b';
                return (
                  <div key={uuid()} className={border}>
                    <Accordion.Toggle accordionItemId={index.toString()}>
                      <span className="inline-block mr-2 bg-black text-white px-2 rounded-full uppercase">
                        {category}
                      </span>
                      <b>{question}</b>
                    </Accordion.Toggle>
                    <Accordion.Collapse accordionItemId={index.toString()}>
                      <ul className="list-disc list-inside">
                        {answers.map((answer: string) => {
                          return <li key={uuid()}>{answer}</li>;
                        })}
                      </ul>
                    </Accordion.Collapse>
                  </div>
                );
              }
            )}
          </>
        </Accordion>
      </Container>
    </div>
  );
};

export default FAQ;
